const results = $input.first().json.results || [];
const monat = new Date().toLocaleDateString('de-DE', { month: 'long', year: 'numeric' });
const heute = new Date().toLocaleDateString('de-DE');

const posts = results.map(page => {
  const props = page.properties;
  const titel = props?.['Titel']?.title?.[0]?.plain_text || 'Ohne Titel';
  const geplantFuer = props?.['Geplant für']?.date?.start || '';
  const saeule = props?.['Säule']?.select?.name || '-';
  return { titel, geplantFuer, saeule };
});

console.log(`📧 Tracking-Erinnerung: ${posts.length} Post(s) ohne Tracking-Daten`);

const postListHtml = posts.map(p => {
  const datum = p.geplantFuer
    ? ' – veröffentlicht am ' + new Date(p.geplantFuer).toLocaleDateString('de-DE')
    : '';
  return `<li><strong>${p.titel}</strong>${datum} <span style="color:#666;font-size:0.9em">(${p.saeule})</span></li>`;
}).join('');

return [{
  json: {
    to: 'wolfgang.baierl@blboardsolutions.de',
    subject: `[LinkedIn] ${posts.length} Post(s) ohne Tracking-Daten – ${monat}`,
    body: `<div style="font-family:Arial,sans-serif;max-width:600px">
<h2 style="color:#2c5282">Tracking-Erinnerung – ${monat}</h2>
<p>Bei <strong>${posts.length}</strong> veröffentlichte(n) Post(s) fehlen noch die Tracking-Daten:</p>
<ul style="line-height:1.8">${postListHtml}</ul>
<hr style="margin:20px 0">
<p><strong>Bitte nachtragen in der Content Pipeline:</strong></p>
<ul>
  <li>Impressionen</li>
  <li>Likes &amp; Kommentare</li>
  <li>Shares</li>
  <li>Profil-Aufrufe</li>
  <li>DMs / Leads</li>
  <li>Neue Kontakte</li>
  <li>Tracking-Datum (= Auswertungsdatum)</li>
</ul>
<p>Die Analyse am letzten Montag im Monat berücksichtigt nur Posts mit vollständigen Tracking-Daten.</p>
<p><a href="https://www.notion.so/35147c762802803f8311ce87bcce27a5" style="background:#2c5282;color:#fff;padding:10px 20px;text-decoration:none;border-radius:4px;display:inline-block">→ Content Pipeline öffnen</a></p>
<p style="color:#999;font-size:0.8em;margin-top:30px">Automatisch generiert am ${heute} · n8n LinkedIn-Workflow</p>
</div>`
  }
}];
